const numbersToWords=Q=>{const s=['','ένα','δύο','τρία','τέσσερα','πέντε','έξι','επτά','οκτώ','εννέα','δέκα','έντεκα','δώδεκα','δεκατρία','δεκατέσσερα','δεκαπέντε','δεκαέξι','δεκαεπτά','δεκαοκτώ','δεκαεννέα'];if(Q<0x14)return s[Q];if(Q<0x64)return['','','είκοσι','τριάντα','σαράντα','πενήντα','εξήντα','εβδομήντα','ογδόντα','ενενήντα'][Math['floor'](Q/0xa)]+(Q%0xa?'\x20'+s[Q%0xa]:'');if(Q<0x3e8){const L=Math['floor'](Q/0x64),C=Q%0x64;return(0x1===L?'εκατό':0x2===L?'διακόσια':0x3===L?'τριακόσια':0x4===L?'τετρακόσια':0x5===L?'πεντακόσια':0x6===L?'εξακόσια':0x7===L?'επτακόσια':0x8===L?'οκτακόσια':0x9===L?'εννιακόσια':'')+(C?'\x20'+numbersToWords(C):'');}return Q<0xf4240?numbersToWords(Math['floor'](Q/0x3e8))+'\x20χιλιάδες'+(Q%0x3e8?'\x20'+numbersToWords(Q%0x3e8):''):numbersToWords(Math['floor'](Q/0xf4240))+'\x20εκατομμύρια'+(Q%0xf4240?'\x20'+numbersToWords(Q%0xf4240):'');},numberToText=(Q,L='money')=>{const C=Math['floor'](Q),a=Math['round'](0x64*(Q-C));let A=numbersToWords(C),P=a>0x0?numbersToWords(a):'';switch(L){case'money':return P?A+'\x20ευρώ\x20και\x20'+P+'\x20λεπτά':A+'\x20ευρώ';case'time':return P?A+'\x20ώρες\x20και\x20'+P+'\x20λεπτά':A+'\x20ώρες';default:return P?A+'\x20και\x20'+P:''+A;}};